```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Item { readonly sku: string; readonly qty: number }

const parseJson = (s: string): E.Either<string, unknown> =>
  E.tryCatch(
    () => JSON.parse(s) as unknown,
    (u) => (u instanceof Error ? u.message : "parse error"),
  );

const extractItems = (j: unknown): E.Either<string, ReadonlyArray<unknown>> => {
  if (typeof j === "object" && j !== null && Array.isArray((j as { items?: unknown }).items)) {
    return E.right((j as { items: ReadonlyArray<unknown> }).items);
  }
  return E.left("missing items array");
};

const checkItems = (items: ReadonlyArray<unknown>): E.Either<string, ReadonlyArray<Item>> => {
  const out: Item[] = [];
  for (const it of items) {
    if (typeof it !== "object" || it === null) return E.left("item not an object");
    const { sku, qty } = it as { sku?: unknown; qty?: unknown };
    if (typeof sku !== "string" || sku.length === 0) return E.left("missing sku");
    out.push({ sku, qty: typeof qty === "number" ? qty : 1 });
  }
  return E.right(out);
};

export const loadInventory = (body: string): E.Either<string, ReadonlyArray<Item>> =>
  pipe(body, parseJson, E.chain(extractItems), E.chain(checkItems));
```

Four stages: parse → flatMap extract → flatMap check. The `Either` short-circuits on the first failure — the downstream stages never see a malformed document.

