import { pipe } from "effect";

const STOP = new Set(["the", "a", "an", "of", "to", "and", "or"]);

const lower = (s: string): string => s.toLowerCase();
const stripPunct = (s: string): string => s.replace(/[^a-z0-9\s]/g, " ");
const splitWs = (s: string): ReadonlyArray<string> => s.split(/\s+/).filter((t) => t.length > 0);
