```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Parsed { readonly hours: number; readonly minutes: number }

const parse = (raw: string): E.Either<string, Parsed> => {
  const m = /^(\d{1,2}):(\d{2})$/.exec(raw.trim());
  if (!m) return E.left(`bad format: ${raw}`);
  return E.right({ hours: Number(m[1]), minutes: Number(m[2]) });
};

// NEW stage between parse and format — the pipeline grew by one line.
// With nested calls this would mean wrapping parse(raw) in another validate(...) layer.
const validate = (p: Parsed): E.Either<string, Parsed> =>
  p.hours >= 0 && p.hours < 24 && p.minutes >= 0 && p.minutes < 60
    ? E.right(p)
    : E.left(`out of range: ${p.hours}:${p.minutes}`);

const format = (p: Parsed): string => `${p.hours.toString().padStart(2, "0")}:${p.minutes.toString().padStart(2, "0")}`;

const withPrefix =
  (prefix: string) =>
  (e: E.Either<string, string>): E.Either<string, string> =>
    pipe(e, E.map((s) => `${prefix}${s}`));

export const normaliseTime = (raw: string): E.Either<string, string> =>
  pipe(parse(raw), E.chain(validate), E.map(format), withPrefix("T:"));
```

The only code change from the original two-stage form was adding `E.chain(validate)` and the later `withPrefix("T:")` as new lines. The earlier and later stages didn't move; pipe makes that kind of edit trivial, and every extra step just adds one line rather than one parenthesis level.

