import { pipe } from "fp-ts/function";

interface Req { readonly loading: boolean; readonly retries: number; readonly lastStart: number }

const clone = (s: Req): Req => ({ ...s });
const setLoading =
  (loading: boolean) =>
  (s: Req): Req => ({ ...s, loading });
const bumpRetries = (s: Req): Req => ({ ...s, retries: s.retries + 1 });
