export const evalCubic = (
  a: number,
  b: number,
  c: number,
  d: number,
  x: number,
): number =>
  pipe(
    a,
    mulAdd(x, b),
    mulAdd(x, c),
    mulAdd(x, d),
  );
```

The pipe form shows Horner's scheme exactly as the mathematical derivation reads: start from the highest coefficient and fold each remaining one in. Nested `mulAdd(x, d)(mulAdd(x, c)(mulAdd(x, b)(a)))` would hide that structure behind parens.

Reach for `pipe` when:

- the pipeline has **three or more stages** — two-step compositions are fine nested,
- the stages are **named**, reusable functions rather than ad-hoc lambdas,
- the data flow matters more than any one transformation in isolation.

Nested calls win only for one- or two-step inline transforms where introducing a pipe would be ceremony.

```ts
import { pipe } from "effect";

interface Raw { readonly width: number; readonly height: number; readonly bytes: number }
interface Meta { readonly width: number; readonly height: number; readonly aspect: number; readonly kb: number }

const addAspect = (r: Raw): Raw & { aspect: number } => ({ ...r, aspect: r.width / r.height });
const addKb = <R extends { bytes: number }>(r: R): R & { kb: number } => ({ ...r, kb: Math.round(r.bytes / 1024) });
const projectMeta = (r: Raw & { aspect: number; kb: number }): Meta => ({
  width: r.width,
  height: r.height,
  aspect: r.aspect,
  kb: r.kb,
});

export const toMeta = (raw: Raw): Meta =>
  pipe(raw, addAspect, addKb, projectMeta);
```

Three stages, each enriching then projecting — the pipeline reads top-to-bottom in the order those facts are computed.

```ts
import { pipe } from "fp-ts/function";

interface Event { readonly ts: number; readonly kind: string }

const sortByTs = (es: ReadonlyArray<Event>): ReadonlyArray<Event> =>
  [...es].sort((a, b) => a.ts - b.ts);
const dayKey = (ts: number): string => new Date(ts).toISOString().slice(0, 10);
const byDay = (es: ReadonlyArray<Event>): Readonly<Record<string, ReadonlyArray<Event>>> => {
  const out: Record<string, Event[]> = {};
  for (const e of es) (out[dayKey(e.ts)] ??= []).push(e);
  return out;
};
const countEach = (
  rec: Readonly<Record<string, ReadonlyArray<Event>>>,
): Readonly<Record<string, number>> =>
  Object.fromEntries(Object.entries(rec).map(([k, v]) => [k, v.length]));

export const dailyEventCounts = (events: ReadonlyArray<Event>): Readonly<Record<string, number>> =>
  pipe(events, sortByTs, byDay, countEach);
```

Three stages, each with a clear responsibility. The type evolves `Event[] -> Event[] -> Record<string, Event[]> -> Record<string, number>` — each stage reads naturally from the one before.

```ts
import { pipe } from "effect";

interface Config { readonly host: string; readonly port: number; readonly debug: boolean }

const DEFAULTS: Config = { host: "localhost", port: 8080, debug: false };

const applyEnv = (env: Readonly<Record<string, string | undefined>>) => (cfg: Config): Config => ({
  ...cfg,
  host: env.APP_HOST ?? cfg.host,
  port: env.APP_PORT !== undefined ? Number(env.APP_PORT) : cfg.port,
  debug: env.APP_DEBUG !== undefined ? env.APP_DEBUG === "1" : cfg.debug,
});

const applyFlags = (flags: Partial<Config>) => (cfg: Config): Config => ({
  ...cfg,
  ...flags,
});

const freeze = (cfg: Config): Readonly<Config> => Object.freeze({ ...cfg });

export const loadConfig = (
  env: Readonly<Record<string, string | undefined>>,
  flags: Partial<Config>,
): Readonly<Config> =>
  pipe(DEFAULTS, applyEnv(env), applyFlags(flags), freeze);
```

The overlay order is visible on the page: defaults first, then env, then flags. Layering with nested calls — `freeze(applyFlags(flags)(applyEnv(env)(DEFAULTS)))` — would obscure which source wins.

```ts
import { pipe } from "fp-ts/function";

const clamp01 = (n: number): number => Math.max(0, Math.min(1, n));
const toPercent = (n: number): number => n * 100;
const round1 = (n: number): number => Math.round(n * 10) / 10;
const render = (n: number): string => `${n.toFixed(1)}%`;

export const formatRatio = (ratio: number): string =>
  pipe(ratio, clamp01, toPercent, round1, render);

// formatRatio(0.12345) === "12.3%"
// formatRatio(-0.5)    === "0.0%"
// formatRatio(2)       === "100.0%"
```

Four stages, each one-line. The clamp-first stage is the reason this function is safer than a naive `${(r * 100).toFixed(1)}%` — but the pipe still reads as a single top-to-bottom recipe.

```ts
import { pipe } from "effect";

const parseAll = (xs: ReadonlyArray<string>): ReadonlyArray<number> => xs.map(Number);
const keepFinite = (xs: ReadonlyArray<number>): ReadonlyArray<number> => xs.filter(Number.isFinite);
const sum = (xs: ReadonlyArray<number>): number => xs.reduce((a, b) => a + b, 0);

// Before (method chain — fine, but each step has to be a method on the carrier):
//   const out = xs.map(parse).filter(isFinite).reduce((a, b) => a + b, 0);
// After — pipe with named, testable free functions:
export const sumParsed = (xs: ReadonlyArray<string>): number =>
  pipe(xs, parseAll, keepFinite, sum);
```

The three stages are individually trivial to unit-test; the pipeline composes them without any class-bound method constraints.

```ts
import { pipe } from "fp-ts/function";

const trim = (s: string): string => s.trim();
const collapseWs = (s: string): string => s.replace(/[ \t]+/g, " ");
const upperPostal = (s: string): string =>
  s.replace(/\b([a-z]{1,2}\d{1,2}[a-z]?\s*\d[a-z]{2})\b/gi, (m) => m.toUpperCase());
const splitCommas = (s: string): ReadonlyArray<string> =>
  s.split(",").map((l) => l.trim()).filter((l) => l.length > 0);

export const normaliseAddress = (raw: string): ReadonlyArray<string> =>
  pipe(raw, trim, collapseWs, upperPostal, splitCommas);
```

Four stages, each cheap to test. Notice the type changes at the final stage (`string -> ReadonlyArray<string>`) — pipe doesn't require stages to share a type, only to line up input-to-output.

```ts
import { pipe } from "fp-ts/function";
import * as O from "fp-ts/Option";

interface User { readonly prefs?: { readonly notifications?: { readonly email?: boolean } } }

export const wantsEmail = (user: User | null | undefined): boolean =>
  pipe(
    O.fromNullable(user),
    O.chainNullableK((u) => u.prefs),
    O.chainNullableK((p) => p.notifications),
    O.chainNullableK((n) => n.email),
    O.getOrElse<boolean>(() => false),
  );
```

Five stages — four stage-level chains plus the final `getOrElse` that exits the `Option`. Nested, this would be `getOrElse(chainNullableK(chainNullableK(chainNullableK(fromNullable(user), ...), ...), ...), ...)`, which is close to unreadable.
